mapper.select:
/* com.matjzing.mapper.FrontTopicMapper.countActiveTopic */
SELECT COUNT(1)
FROM TOPIC
WHERE TOPIC_SEQ = #{topicSeq}
  AND USE_YN = TRUE

/* com.matjzing.mapper.FrontTopicMapper.selectFrontTopicList */ SELECT t.TOPIC_SEQ /**/ , AS memberSeq , t.CATEGORY_SEQ /**/ , t.CANDIDATE_SEQ /**/ , (SELECT NAME FROM CATEGORY WHERE CATEGORY_SEQ = t.CATEGORY_SEQ) AS CATEGORY_NAME , t.EMOJI , t.TITLE /**/ , t.STATUS /**/ , t.GOOGLE_EVENT_ID /**/ , t.USE_YN /**/ , t.REGISTER_SEQ /**/ , t.REGISTER_IP /**/ , t.REGISTRATION_DT /**/ , t.UPDATER_SEQ /**/ , t.UPDATER_IP /**/ , t.UPDATE_DT /**/ FROM TOPIC t WHERE t.USE_YN = true
AND EXISTS ( SELECT 1 FROM TOPIC_MEMBER tm WHERE tm.TOPIC_SEQ = t.TOPIC_SEQ AND tm.MEMBER_SEQ = #{memberSeq} AND tm.USE_YN = TRUE )
AND 1 = 0
AND t.CATEGORY_SEQ = #{categorySeq}

/* com.matjzing.mapper.FrontTopicMapper.selectFrontTopicPage */ SELECT t.TOPIC_SEQ /**/ , AS memberSeq , t.CATEGORY_SEQ /**/ , t.CANDIDATE_SEQ /**/ , (SELECT NAME FROM CATEGORY WHERE CATEGORY_SEQ = t.CATEGORY_SEQ) AS CATEGORY_NAME , t.EMOJI , t.TITLE /**/ , t.STATUS /**/ , t.GOOGLE_EVENT_ID /**/ , t.USE_YN /**/ , t.REGISTER_SEQ /**/ , t.REGISTER_IP /**/ , t.REGISTRATION_DT /**/ , t.UPDATER_SEQ /**/ , t.UPDATER_IP /**/ , t.UPDATE_DT /**/ FROM TOPIC t WHERE t.USE_YN = true
AND EXISTS ( SELECT 1 FROM TOPIC_MEMBER tm WHERE tm.TOPIC_SEQ = t.TOPIC_SEQ AND tm.MEMBER_SEQ = #{memberSeq} AND tm.USE_YN = TRUE )
AND 1 = 0
AND t.CATEGORY_SEQ = #{categorySeq}

/* com.matjzing.mapper.FrontTopicMapper.selectFrontTopic */ SELECT t.TOPIC_SEQ /**/ , AS memberSeq , t.CATEGORY_SEQ /**/ , t.CANDIDATE_SEQ /**/ , (SELECT NAME FROM CATEGORY WHERE CATEGORY_SEQ = t.CATEGORY_SEQ) AS CATEGORY_NAME , t.EMOJI , t.TITLE /**/ , t.STATUS /**/ , t.GOOGLE_EVENT_ID /**/ , t.USE_YN /**/ , t.REGISTER_SEQ /**/ , t.REGISTER_IP /**/ , t.REGISTRATION_DT /**/ , t.UPDATER_SEQ /**/ , t.UPDATER_IP /**/ , t.UPDATE_DT /**/ FROM TOPIC t WHERE t.TOPIC_SEQ = #{topicSeq} AND t.USE_YN = TRUE
AND EXISTS ( SELECT 1 FROM TOPIC_MEMBER tm WHERE tm.TOPIC_SEQ = t.TOPIC_SEQ AND tm.MEMBER_SEQ = #{memberSeq} AND tm.ROLE_TYPE = 'OWNER' AND tm.USE_YN = TRUE )
AND 1 = 0

mapper.insert:
/* com.matjzing.mapper.FrontTopicMapper.insertFrontTopic */
INSERT INTO TOPIC (
	  CATEGORY_SEQ /**/
	, EMOJI
	, TITLE /**/
	, GOOGLE_EVENT_ID /**/
	, USE_YN /**/
	, REGISTER_SEQ /**/
	, REGISTER_IP /**/
	, REGISTRATION_DT /**/
	, UPDATER_SEQ /**/
	, UPDATER_IP /**/
	, UPDATE_DT /**/
) VALUES (
	  #{categorySeq}
	, #{emoji}
	, #{title}
	, #{googleEventId}
	, TRUE
	, #{registerSeq}
	, #{registerIp}
	, NOW(3)
	, #{updaterSeq}
	, #{updaterIp}
	, NOW(3)
)

/* com.matjzing.mapper.FrontTopicMapper.insertTopicMember */
INSERT IGNORE INTO TOPIC_MEMBER (
	  TOPIC_SEQ /**/
	, MEMBER_SEQ /**/
	, ROLE_TYPE /**/
	, JOIN_DT /**/
	, USE_YN /**/
	, REGISTER_SEQ /**/
	, REGISTER_IP /**/
	, REGISTRATION_DT /**/
	, UPDATER_SEQ /**/
	, UPDATER_IP /**/
	, UPDATE_DT /**/
) VALUES (
	  #{topicSeq}
	, COALESCE(#{memberSeq}, #{registerSeq})
	, 'OWNER'
	, NOW(3)
	, TRUE
	, #{registerSeq}
	, #{registerIp}
	, NOW(3)
	, #{updaterSeq}
	, #{updaterIp}
	, NOW(3)
)

/* com.matjzing.mapper.FrontTopicMapper.insertTopicParticipant */
INSERT IGNORE INTO TOPIC_MEMBER (
	  TOPIC_SEQ /**/
	, MEMBER_SEQ /**/
	, ROLE_TYPE /**/
	, JOIN_DT /**/
	, USE_YN /**/
	, REGISTER_SEQ /**/
	, REGISTER_IP /**/
	, REGISTRATION_DT /**/
	, UPDATER_SEQ /**/
	, UPDATER_IP /**/
	, UPDATE_DT /**/
) VALUES (
	  #{topicSeq}
	, COALESCE(#{memberSeq}, #{registerSeq})
	, 'PARTICIPANT'
	, NOW(3)
	, TRUE
	, #{registerSeq}
	, #{registerIp}
	, NOW(3)
	, #{updaterSeq}
	, #{updaterIp}
	, NOW(3)
)

mapper.update:
/* com.matjzing.mapper.FrontTopicMapper.updateFrontTopic */ UPDATE TOPIC SET UPDATER_SEQ = #{updaterSeq} /*수정자_시퀀스*/ , UPDATER_IP = #{updaterIp} /*수정자_아이피*/ , UPDATE_DT = NOW(3) /*수정_일시*/ , EMOJI = #{emoji} /**/ , TITLE = #{title} /**/ , GOOGLE_EVENT_ID = #{googleEventId} /**/ WHERE TOPIC_SEQ = #{topicSeq} AND USE_YN = TRUE
AND EXISTS ( SELECT 1 FROM TOPIC_MEMBER tm WHERE tm.TOPIC_SEQ = #{topicSeq} AND tm.MEMBER_SEQ = #{memberSeq} AND tm.ROLE_TYPE = 'OWNER' AND tm.USE_YN = TRUE )
AND 1 = 0

/* com.matjzing.mapper.FrontTopicMapper.deleteFrontTopic */ UPDATE TOPIC SET UPDATER_SEQ = #{updaterSeq} /*수정자_시퀀스*/ , UPDATER_IP = #{updaterIp} /*수정자_아이피*/ , UPDATE_DT = NOW(3) /*수정_일시*/ , USE_YN = FALSE WHERE TOPIC_SEQ = #{topicSeq} AND USE_YN = TRUE
AND EXISTS ( SELECT 1 FROM TOPIC_MEMBER tm WHERE tm.TOPIC_SEQ = #{topicSeq} AND tm.MEMBER_SEQ = #{memberSeq} AND tm.ROLE_TYPE = 'OWNER' AND tm.USE_YN = TRUE )
AND 1 = 0
